<script setup lang="ts">
import{computed,onMounted,ref}from'vue'
import{api}from'../api/client'
import{useAuthStore}from'../stores/auth'
const auth=useAuthStore(),rows=ref<any[]>([]),discover=ref<any[]>([]),selected=ref<any>(),students=ref<any[]>([]),requests=ref<any[]>([]),managers=ref<any[]>([]),teachers=ref<any[]>([]),importFile=ref<File>(),defaultPassword=ref('Student123!'),importResult=ref<any>(),managerId=ref<number>(),reason=ref(''),form=ref({name:'',subject:'',grade_level:'',description:''}),error=ref(''),message=ref('')
const canCreate=computed(()=>['teacher','admin'].includes(auth.user?.role||'')),isStudent=computed(()=>auth.user?.role==='student')
async function load(){rows.value=(await api.get('/courses')).data;if(isStudent.value)discover.value=(await api.get('/courses/discover')).data}
async function create(){try{error.value='';await api.post('/courses',form.value);message.value='课程创建成功';form.value={name:'',subject:'',grade_level:'',description:''};await load()}catch(e:any){error.value=e.message}}
async function apply(course:any){try{await api.post(`/courses/${course.id}/join-requests`,{reason:reason.value||null});course.request_status='pending';message.value='申请已提交，等待课程负责人审批'}catch(e:any){error.value=e.message}}
async function manage(course:any){if(!course.is_manager)return;selected.value=course;const [s,r,m,t]=await Promise.all([api.get(`/courses/${course.id}/students`),api.get(`/courses/${course.id}/join-requests`),api.get(`/courses/${course.id}/managers`),api.get('/users?role=teacher')]);students.value=s.data;requests.value=r.data;managers.value=m.data;teachers.value=t.data;managerId.value=teachers.value[0]?.id}
async function review(id:number,action:string){try{await api.patch(`/course-join-requests/${id}`,{action,comment:action==='approve'?'同意加入课程':'暂不符合加入条件'});message.value='申请已处理';await manage(selected.value)}catch(e:any){error.value=e.message}}
function pickImport(e:Event){importFile.value=(e.target as HTMLInputElement).files?.[0]}
async function importStudents(){if(!importFile.value)return;const data=new FormData();data.append('default_password',defaultPassword.value);data.append('file',importFile.value);try{importResult.value=(await api.post(`/courses/${selected.value.id}/students/import`,data)).data;message.value=`导入完成：成功 ${importResult.value.success}，已有 ${importResult.value.existing}，失败 ${importResult.value.failed}`;await manage(selected.value)}catch(e:any){error.value=e.message}}
async function addManager(){if(!managerId.value)return;try{await api.post(`/courses/${selected.value.id}/managers`,{user_id:managerId.value});message.value='课程负责人已添加';await manage(selected.value)}catch(e:any){error.value=e.message}}
onMounted(()=>load().catch(e=>error.value=e.message))
</script>
<template><div class="page"><div class="page-title"><div><h1>{{canCreate?'课程中心':'我的课程'}}</h1><p>{{canCreate?'所有教师可查看课程信息；只有负责人可以管理成员、备课、作业和答疑。':'只有审批加入的课程才会出现在“我的课程”中。'}}</p></div></div><p class="notice success-box" v-if="message">{{message}}</p><p class="notice error" v-if="error">{{error}}</p><div v-if="canCreate" class="card"><h2>创建新课程</h2><div class="form-grid"><label>课程名称<input v-model="form.name" placeholder="例如：机器学习基础"></label><label>学科<input v-model="form.subject" placeholder="例如：计算机"></label><label>年级/学段<input v-model="form.grade_level" placeholder="例如：本科二年级"></label></div><label>课程描述<textarea v-model="form.description" placeholder="介绍课程内容和学习目标"/></label><button @click="create">创建课程</button></div><div class="card"><h2>{{canCreate?'全部课程':'已加入课程'}} <span class="badge">{{rows.length}}</span></h2><div v-if="!rows.length" class="empty">暂无课程</div><div class="course-grid"><article v-for="x in rows" :key="x.id" class="course-card"><div class="course-subject">{{x.subject}}</div><h3>{{x.name}}</h3><p>{{x.description||'暂无课程描述'}}</p><div class="meta"><span>{{x.grade_level||'未设置学段'}}</span><span v-if="x.is_manager" class="status approved">我负责的课程</span></div><button v-if="canCreate&&x.is_manager" @click="manage(x)">成员与负责人</button> <router-link :to="`/knowledge?course=${x.id}`" class="button-link secondary">查看知识库</router-link></article></div></div><div v-if="isStudent" class="card"><h2>发现课程</h2><div v-if="!discover.length" class="empty">暂无其他可申请课程</div><div class="course-grid"><article v-for="x in discover" class="course-card"><div class="course-subject">{{x.subject}}</div><h3>{{x.name}}</h3><p>{{x.description||'暂无课程描述'}}</p><textarea v-if="!x.request_status||x.request_status==='rejected'" v-model="reason" placeholder="申请理由（可选）"></textarea><button v-if="!x.request_status||x.request_status==='rejected'" @click="apply(x)">申请加入</button><span v-else :class="['status',x.request_status==='pending'?'pending_review':'approved']">{{x.request_status==='pending'?'等待审批':x.request_status}}</span></article></div></div><div v-if="selected&&canCreate" class="modal-backdrop" @click.self="selected=null"><div class="modal wide"><button class="modal-close" @click="selected=null">×</button><h2>{{selected.name}} · 课程成员管理</h2><div class="management-grid"><section><h3>批量导入学生</h3><p class="muted">CSV 表头必须含 username、display_name，可选 email、password。</p><input type="file" accept=".csv" @change="pickImport"><label>统一初始密码<input type="password" v-model="defaultPassword"></label><button :disabled="!importFile" @click="importStudents">导入名单</button><div v-if="importResult" class="batch-results"><div v-for="x in importResult.results" :class="['upload-result',x.status==='failed'?'failed':'ready']">{{x.username}} · {{x.status}} <span>{{x.message}}</span></div></div></section><section><h3>待审批申请 <span class="badge">{{requests.length}}</span></h3><div v-if="!requests.length" class="empty">暂无待审批申请</div><div v-for="r in requests" class="request-item"><div><strong>{{r.student_name}}</strong><small>@{{r.username}} · {{r.reason||'未填写理由'}}</small></div><button @click="review(r.id,'approve')">同意</button><button class="danger" @click="review(r.id,'reject')">拒绝</button></div></section><section><h3>课程负责人</h3><div v-for="m in managers" class="member-row"><span>{{m.display_name}}（{{m.username}}）</span><span class="status approved">负责人</span></div><div class="inline-actions"><select v-model.number="managerId"><option v-for="t in teachers" :value="t.id">{{t.display_name}}（{{t.username}}）</option></select><button @click="addManager">添加负责人</button></div></section><section><h3>已加入学生 <span class="badge">{{students.length}}</span></h3><div v-if="!students.length" class="empty">暂无学生</div><div v-for="s in students" class="member-row"><span>{{s.display_name}}（{{s.username}}）</span><small>{{s.source}}</small></div></section></div></div></div></div></template>
